+function processPairTrackingModifier(
+    query: QueryInstance,
+    modifier: Modifier,
+    logic: 'and' | 'or',
+    groupsMap: Map<string, PairTrackingGroup>
+) {
+    const type = getTrackingType(modifier);
+    const pairs = modifier.pairs;
+    if (!type || !pairs?.length) return;
+    const key = `${type}-${modifier.id}-${logic}`;
+    let group = groupsMap.get(key);
+    if (!group) {
+        group = { logic, type, id: modifier.id, pairs: [], events: new Map() };
+        groupsMap.set(key, group);
+        query.pairTrackingGroups.push(group);
+    }
+    group.pairs.push(...pairs);
+    query.isTracking = true;
+}
+
+function checkPairTracking(query: QueryInstance, entity: Entity, eventType: EventType, pair: RelationPair) {
+    const eid = getEntityId(entity);
+    const target = pair[$internal].target;
+    if (typeof target !== 'number') return false;
+    for (const group of query.pairTrackingGroups) {
+        let affects = false;
+        for (const tracked of group.pairs) {
+            const ctx = tracked[$internal];
+            if (ctx.relation !== pair[$internal].relation || (ctx.target !== '*' && ctx.target !== target)) continue;
+            affects = true;
+            const events = group.events.get(eid) ?? new Map<number, EventType>();
+            const prior = events.get(target);
+            // Opposite events for the same pair cancel within this observation window.
+            if ((prior === 'add' && eventType === 'remove') || (prior === 'remove' && eventType === 'add')) events.delete(target);
+            else events.set(target, eventType);
+            if (events.size) group.events.set(eid, events);
+            else group.events.delete(eid);
+            break;
+        }
+        if (!affects) continue;
+    }
+
+    // Pair modifiers are additive constraints; regular required/forbidden/or constraints
+    // are checked by the normal query matcher before this is called by relation events.
+    let hasOr = false;
+    let orMatched = false;
+    for (const group of query.pairTrackingGroups) {
+        const events = group.events.get(eid);
+        let matched = false;
+        if (events) {
+            for (const tracked of group.pairs) {
+                const trackedTarget = tracked[$internal].target;
+                if (trackedTarget === '*') {
+                    for (const value of events.values()) if (value === group.type) { matched = true; break; }
+                } else if (typeof trackedTarget === 'number' && events.get(trackedTarget) === group.type) matched = true;
+                if (matched) break;
+            }
+        }
+        if (group.logic === 'or') { hasOr = true; orMatched ||= matched; }
+        else if (!matched) return false;
+    }
+    return !hasOr || orMatched;
+}
